        { "french": "émerveiller", "german": "in Erstaunen versetzen", "exampleFrench": "Le pouvoir du roi n'émerveillait pas le petit prince.", "exampleGerman": "Die Macht des Königs versetzte den kleinen Prinzen nicht in Erstaunen." },
        { "french": "s'enquérir de (qn/qc)", "german": "sich erkundigen (nach)", "exampleFrench": "Le roi s'enquit de l'état de sa planète.", "exampleGerman": "Der König erkundigte sich nach dem Zustand seines Planeten." },
        { "french": "s'enhardir", "german": "Mut fassen", "exampleFrench": "Le petit prince s'enhardit à demander une faveur.", "exampleGerman": "Der kleine Prinz fasste Mut und bat um einen Gefallen." },
        { "french": "être dans son tort", "german": "im Unrecht sein", "exampleFrench": "Si tu ordonnes l'impossible, tu seras dans ton tort.", "exampleGerman": "Wenn du das Unmögliche befiehlst, wirst du im Unrecht sein." },
        { "french": "exiger (qc)", "german": "verlangen, fordern", "exampleFrench": "Il faut exiger de chacun ce que chacun peut donner.", "exampleGerman": "Man muss von jedem das fordern, was jeder geben kann." },
        { "french": "gracier (qn)", "german": "begnadigen", "exampleFrench": "Le roi pourrait gracier le vieux rat.", "exampleGerman": "Der König könnte die alte Ratte begnadigen." },
        { "french": "hermine (f)", "german": "Hermelin", "exampleFrench": "Le roi portait un grand manteau d'hermine.", "exampleGerman": "Der König trug einen großen Hermelinmantel." },
        { "french": "obéir à qn", "german": "jdm gehorchen", "exampleFrench": "Le petit prince ne voulait pas obéir à un ordre déraisonnable.", "exampleGerman": "Der kleine Prinz wollte einem unvernünftigen Befehl nicht gehorchen." },
        { "french": "l’obéissance (f)", "german": "der Gehorsam", "exampleFrench": "L'obéissance est la première règle du royaume.", "exampleGerman": "Gehorsam ist die erste Regel des Königreichs." },
        { "french": "ordonner (qc)", "german": "befehlen", "exampleFrench": "Le roi ne pouvait ordonner qu'une chose raisonnable.", "exampleGerman": "Der König konnte nur etwas Vernünftiges befehlen." },
        { "french": "un pan", "german": "ein Zipfel, Stück (eines Kleidungsstücks)", "exampleFrench": "Le roi était couvert par un pan de son manteau.", "exampleGerman": "Der König war von einem Zipfel seines Mantels bedeckt." },
        { "french": "paraître", "german": "erscheinen, scheinen", "exampleFrench": "Le roi paraissait régner sur tout.", "exampleGerman": "Der König schien über alles zu herrschen." },
        { "french": "peiner (qn)", "german": "betrüben, Kummer bereiten", "exampleFrench": "Le départ du petit prince peinait le vieux roi.", "exampleGerman": "Die Abreise des kleinen Prinzen betrübte den alten König." },
        { "french": "raisonnable", "german": "vernünftig", "exampleFrench": "Un ordre doit être raisonnable pour être exécuté.", "exampleGerman": "Ein Befehl muss vernünftig sein, um ausgeführt zu werden." },
        { "french": "rougir", "german": "erröten", "exampleFrench": "Le petit prince rougit un peu.", "exampleGerman": "Der kleine Prinz errötete ein wenig." },
        { "french": "un sage (m)", "german": "ein Weiser", "exampleFrench": "Un sage ne donne que des ordres raisonnables.", "exampleGerman": "Ein Weiser gibt nur vernünftige Befehle." },
        { "french": "sage (adj.)", "german": "weise, klug", "exampleFrench": "Ses paroles étaient très sages.", "exampleGerman": "Seine Worte waren sehr weise." },
        { "french": "siéger", "german": "den Vorsitz führen, thronen", "exampleFrench": "Le roi siégeait sur un trône très simple.", "exampleGerman": "Der König thronte auf einem sehr einfachen Thron." },
        { "french": "tantôt", "german": "bald... bald", "exampleFrench": "Le roi ordonnait tantôt au soleil de se coucher.", "exampleGerman": "Der König befahl der Sonne bald unterzugehen." },
        { "french": "le trône", "german": "der Thron", "exampleFrench": "Le trône du roi occupait presque toute la planète.", "exampleGerman": "Der Thron des Königs nahm fast den ganzen Planeten ein." },
        { "french": "vexé(e)", "german": "gekränkt, verärgert", "exampleFrench": "Le petit prince était vexé de ne pas obtenir son coucher de soleil.", "exampleGerman": "Der kleine Prinz war gekränkt, weil er seinen Sonnenuntergang nicht bekam." }
